parameters.jsCode:
// Pegamos os dois campos de onde o WhatsApp envia os JIDs
const jid1 = $input.first().json.body.data.key.remoteJid || "";
const jid2 = $input.first().json.body.data.key.remoteJidAlt || "";

// Variável onde vamos guardar o correto
let correctJid = "";

// Testa qual deles possui "@s.whatsapp.net"
if (jid1.includes("@s.whatsapp.net")) {
  correctJid = jid1;
} else if (jid2.includes("@s.whatsapp.net")) {
  correctJid = jid2;
}

// Retornamos somente o que é válido
return [
  {
    json: {
      selectedNumber: correctJid
    }
  }
];
